function App() {
  const [currentRole, setCurrentRole] = useState<Role | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginError, setLoginError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [toasts, setToasts] = useState<{id: string, message: string, type: 'success' | 'error'}[]>([]);

  // App Data State
  const [users, setUsers] = useState<User[]>([]);
  const [orders, setOrders] = useState<ServiceOrder[]>([]);
  const [timeRecords, setTimeRecords] = useState<TimeRecord[]>([]);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [hrRequests, setHrRequests] = useState<HRRequest[]>([]);
  const [reports, setReports] = useState<ServiceReport[]>([]);

  // Carregar dados iniciais do Back4App
  useEffect(() => {
    async function init() {
      try {
        const user = await parseService.getCurrentUser();
        if (user) {
          setCurrentUser(user);
          setCurrentRole(user.role);
          await loadAllData();
        }
      } catch (e) {
        console.error("Erro ao verificar sessão:", e);
      } finally {
        setInitialLoading(false);
      }
    }
    init();
  }, []);

  const loadAllData = async () => {
    try {
      const [ord, tkt, emp, rep] = await Promise.all([
        parseService.getOrders(),
        parseService.getTickets(),
        parseService.getEmployees(),
        parseService.getReports()
      ]);
      setOrders(ord);
      setTickets(tkt);
      setUsers(emp);
      setReports(rep);
    } catch (e) {
      console.error("Erro ao carregar dados:", e);
      addToast("Erro ao sincronizar com servidor", "error");
    }
  };

  const addToast = (message: string, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  };

  const handleLoginAttempt = async (email: string, pass: string) => {
    setLoading(true);
    setLoginError(null);
    try {
      const user = await parseService.login(email, pass);
      setCurrentUser(user);
      setCurrentRole(user.role);
      await loadAllData();
    } catch (e: any) {
      setLoginError(e.message || "Erro de autenticação");
    } finally {
      setLoading(false);
    }
  };

  const handleCreateOrder = async (newOrder: ServiceOrder) => {
    try {
      const saved = await parseService.saveOrder(newOrder);
      setOrders(prev => [saved, ...prev]);
      addToast("Ordem de serviço salva na nuvem!");
    } catch (e) {
      addToast("Erro ao salvar ordem", "error");
    }
  };

  const handleUpdateOrderStatus = async (orderId: string, status: OrderStatus) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;
    try {
      const updated = await parseService.saveOrder({ ...order, status });
      setOrders(prev => prev.map(o => o.id === orderId ? updated : o));
      addToast(`Status atualizado: ${status}`);
    } catch (e) {
      addToast("Erro ao atualizar status", "error");
    }
  };

  const handleClockAction = async (type: 'CLOCK_IN' | 'CLOCK_OUT') => {
    // Implementar lógica de ponto no Parse aqui se necessário
    addToast("Ponto registrado com sucesso!");
  };

  const handleCreateTicket = async (ticketData: Omit<Ticket, 'id' | 'createdAt' | 'messages'>) => {
    try {
      const saved = await parseService.saveTicket({ ...ticketData, createdAt: new Date().toISOString(), messages: [] });
      setTickets(prev => [saved, ...prev]);
      addToast("Chamado enviado ao Back4App");
    } catch (e) {
      addToast("Erro ao abrir chamado", "error");
    }
  };

  const handleUpdateTicketStatus = async (ticketId: string, status: TicketStatus) => {
    try {
      const ticket = tickets.find(t => t.id === ticketId);
      if (ticket) {
        const updated = await parseService.saveTicket({ ...ticket, status });
        setTickets(prev => prev.map(t => t.id === ticketId ? updated : t));
        addToast("Ticket atualizado no servidor");
      }
    } catch (e) {
      addToast("Erro ao atualizar ticket", "error");
    }
  };

  const handleReplyTicket = async (ticketId: string, messageText: string) => {
    const ticket = tickets.find(t => t.id === ticketId);
    if (!ticket) return;
    const newMessage: ChatMessage = { id: Date.now().toString(), sender: 'admin', text: messageText, timestamp: new Date().toISOString() };
    try {
      const updated = await parseService.saveTicket({ ...ticket, messages: [...ticket.messages, newMessage], status: TicketStatus.IN_PROGRESS });
      setTickets(prev => prev.map(t => t.id === ticketId ? updated : t));
    } catch (e) {
      addToast("Erro ao enviar resposta", "error");
    }
  };

  const handleSaveEmployee = async (employeeData: Partial<User>) => {
    try {
      const updated = await parseService.saveEmployee(employeeData);
      setUsers(prev => prev.map(u => u.id === updated.id ? updated : u));
      addToast("Funcionário atualizado no backend");
    } catch (e) {
      addToast("Erro ao salvar funcionário", "error");
    }
  };

  const handleCreateReport = async (report: ServiceReport) => {
    try {
      const saved = await parseService.saveReport(report);
      setReports(prev => [saved, ...prev]);
      handleUpdateOrderStatus(report.orderId, OrderStatus.COMPLETED);
      addToast("Relatório persistido no Back4App");
    } catch (e) {
      addToast("Erro ao salvar relatório", "error");
    }
  };

  if (initialLoading) {
    return (
      <div className="h-screen bg-black flex flex-col items-center justify-center text-white">
        <Loader2 className="animate-spin mb-4" size={48} />
        <p className="animate-pulse font-bold tracking-widest text-xs uppercase">Sincronizando Dados SaaS...</p>
      </div>
    );
  }

  if (!currentRole || !currentUser) {
    return <LoginScreen onLogin={handleLoginAttempt} error={loginError} loading={loading} />;
  }

  return (
    <div className="font-sans antialiased text-slate-900 h-screen overflow-hidden selection:bg-blue-500 selection:text-white">
      <ToastContainer toasts={toasts} />

      {currentRole === 'ADMIN' && (
        <AdminView 
          orders={orders} 
          employees={users} 
          timeRecords={timeRecords}
          tickets={tickets}
          hrRequests={hrRequests}
          reports={reports}
          onCreateOrder={handleCreateOrder}
          onUpdateTicketStatus={handleUpdateTicketStatus}
          onReplyTicket={handleReplyTicket}
          onSaveEmployee={handleSaveEmployee}
          onHRRequestAction={() => {}} // TODO: Implementar no Parse
        />
      )}

      {currentRole === 'EMPLOYEE' && (
        <EmployeeView 
          currentUser={currentUser}
          orders={orders}
          timeRecords={timeRecords}
          onUpdateOrderStatus={handleUpdateOrderStatus}
          onClockAction={handleClockAction}
          onCreateReport={handleCreateReport}
        />
      )}

      {currentRole === 'CLIENT' && (
        <ClientView 
          currentUser={currentUser}
          tickets={tickets}
          reports={reports.filter(r => r.clientName === currentUser.name || r.clientName === 'Tech Solutions Ltda')} 
          onCreateTicket={handleCreateTicket}
        />
      )}
    </div>
  );
}

export default App;

import Parse from 'parse';
import { User, ServiceOrder, Ticket, HRRequest, ServiceReport, TimeRecord, Role } from '../types';

// CONFIGURAÇÃO: Substitua pelos seus IDs do Back4App
const APP_ID = "YOUR_BACK4APP_APP_ID";
const JS_KEY = "YOUR_BACK4APP_JS_KEY";

Parse.initialize(APP_ID, JS_KEY);
Parse.serverURL = 'https://pg-app.back4app.com/';

export const parseService = {
  // Autenticação
  async login(email: string, pass: string): Promise<User> {
    const parseUser = await Parse.User.logIn(email, pass);
    return this.mapParseUser(parseUser);
  },

  async logout() {
    await Parse.User.logOut();
  },

  async getCurrentUser(): Promise<User | null> {
    const currentUser = Parse.User.current();
    return currentUser ? this.mapParseUser(currentUser) : null;
  },

  // Gestão de Usuários (Centralizada)
  async getUsers(): Promise<User[]> {
    const query = new Parse.Query(Parse.User);
    const results = await query.find();
    return results.map(u => this.mapParseUser(u));
  },

  async saveUser(userData: Partial<User> & { password?: string }): Promise<User> {
    if (!userData.id) {
      // Novo Usuário
      const user = new Parse.User();
      user.set("username", userData.email);
      user.set("email", userData.email);
      user.set("password", userData.password || "123456"); // Senha padrão se não informada
      user.set("name", userData.name);
      user.set("role", userData.role);
      user.set("department", userData.department);
      user.set("position", userData.position);
      user.set("salary", userData.salary);
      user.set("hireDate", userData.hireDate);
      user.set("status", userData.status || "active");
      user.set("avatar", `https://api.dicebear.com/7.x/avataaars/svg?seed=${userData.name}`);

      const savedUser = await user.signUp();
      return this.mapParseUser(savedUser);
    } else {
      // Atualizar Usuário Existente
      const query = new Parse.Query(Parse.User);
      const user = await query.get(userData.id);

      if (userData.name) user.set("name", userData.name);
      if (userData.role) user.set("role", userData.role);
      if (userData.department) user.set("department", userData.department);
      if (userData.position) user.set("position", userData.position);
      if (userData.salary) user.set("salary", userData.salary);
      if (userData.hireDate) user.set("hireDate", userData.hireDate);
      if (userData.status) user.set("status", userData.status);
      if (userData.password) user.set("password", userData.password);

      await user.save();
      return this.mapParseUser(user);
    }
  },

  // Ordens de Serviço
  async getOrders(): Promise<ServiceOrder[]> {
    const query = new Parse.Query("ServiceOrder");
    query.descending("createdAt");
    const results = await query.find();
    return results.map(r => ({
      id: r.id,
      ...r.attributes
    } as ServiceOrder));
  },

  async saveOrder(order: ServiceOrder): Promise<ServiceOrder> {
    const OrderObj = Parse.Object.extend("ServiceOrder");
    const obj = order.id ? (await new Parse.Query("ServiceOrder").get(order.id)) : new OrderObj();
    await obj.save(order);
    return { ...order, id: obj.id };
  },

  // Chamados de Suporte
  async getTickets(): Promise<Ticket[]> {
    const query = new Parse.Query("Ticket");
    query.descending("createdAt");
    const results = await query.find();
    return results.map(r => ({
      id: r.id,
      ...r.attributes
    } as Ticket));
  },

  async saveTicket(ticket: Partial<Ticket>): Promise<Ticket> {
    const TicketObj = Parse.Object.extend("Ticket");
    const obj = ticket.id ? (await new Parse.Query("Ticket").get(ticket.id)) : new TicketObj();
    await obj.save(ticket);
    return { ...ticket, id: obj.id } as Ticket;
  },

  // Relatórios
  async getReports(): Promise<ServiceReport[]> {
    const query = new Parse.Query("ServiceReport");
    const results = await query.find();
    return results.map(r => ({ id: r.id, ...r.attributes } as ServiceReport));
  },

  async saveReport(report: ServiceReport): Promise<ServiceReport> {
    const ReportObj = Parse.Object.extend("ServiceReport");
    const obj = new ReportObj();
    await obj.save(report);
    return { ...report, id: obj.id };
  },

  // Helper de mapeamento
  mapParseUser(u: Parse.User): User {
    return {
      id: u.id,
      name: u.get("name") || u.get("username"),
      email: u.get("email"),
      role: u.get("role") as Role,
      avatar: u.get("avatar"),
      department: u.get("department"),
      position: u.get("position"),
      salary: u.get("salary"),
      hireDate: u.get("hireDate"),
      status: u.get("status")
    };
  }
};

