function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginError, setLoginError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [toasts, setToasts] = useState<{id: string, message: string, type: 'success' | 'error'}[]>([]);

  // App Data State
  const [users, setUsers] = useState<User[]>([]);
  const [orders, setOrders] = useState<ServiceOrder[]>([]);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [reports, setReports] = useState<ServiceReport[]>([]);

  useEffect(() => {
    async function init() {
      try {
        const user = await parseService.getCurrentUser();
        if (user) {
          setCurrentUser(user);
          await loadAllData();
        }
      } catch (e) {
        console.error("Erro na sessão:", e);
      } finally {
        setInitialLoading(false);
      }
    }
    init();
  }, []);

  const loadAllData = async () => {
    try {
      const [ord, tkt, emp, rep] = await Promise.all([
        parseService.getOrders(),
        parseService.getTickets(),
        parseService.getUsers(),
        parseService.getReports()
      ]);
      setOrders(ord);
      setTickets(tkt);
      setUsers(emp);
      setReports(rep);
    } catch (e) {
      console.error("Erro ao carregar dados:", e);
    }
  };

  const addToast = (message: string, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  };

  const handleLoginAttempt = async (email: string, pass: string) => {
    setLoading(true);
    setLoginError(null);
    try {
      const user = await parseService.login(email, pass);
      setCurrentUser(user);
      await loadAllData();
      addToast(`Bem-vindo, ${user.name}!`);
    } catch (e: any) {
      setLoginError("Credenciais inválidas ou erro de conexão.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveUser = async (userData: Partial<User> & { password?: string }) => {
    try {
      const saved = await parseService.saveUser(userData);
      setUsers(prev => {
        const exists = prev.find(u => u.id === saved.id);
        if (exists) return prev.map(u => u.id === saved.id ? saved : u);
        return [saved, ...prev];
      });
      addToast(userData.id ? "Perfil atualizado!" : "Novo usuário cadastrado!");
    } catch (e: any) {
      addToast(e.message || "Erro ao salvar usuário", "error");
    }
  };

  // ... Outros handlers (Orders, Tickets, Reports) permanecem os mesmos, chamando parseService

  if (initialLoading) {
    return <div className="h-screen bg-black flex items-center justify-center"><Loader2 className="animate-spin text-white" size={48} /></div>;
  }

  if (!currentUser) {
    return <LoginScreen onLogin={handleLoginAttempt} error={loginError} loading={loading} />;
  }

  return (
    <div className="font-sans antialiased text-slate-900 h-screen overflow-hidden">
      <ToastContainer toasts={toasts} />

      {currentUser.role === 'ADMIN' && (
        <AdminView 
          orders={orders} 
          employees={users} 
          timeRecords={[]} // Simplificado
          tickets={tickets}
          hrRequests={[]} // Simplificado
          reports={reports}
          onCreateOrder={async (o) => { await parseService.saveOrder(o); loadAllData(); }}
          onUpdateTicketStatus={async (id, s) => { await parseService.saveTicket({id, status: s}); loadAllData(); }}
          onReplyTicket={async (id, m) => { /* logic */ }}
          onSaveEmployee={handleSaveUser}
          onHRRequestAction={() => {}}
        />
      )}

      {currentUser.role === 'EMPLOYEE' && (
        <EmployeeView 
          currentUser={currentUser}
          orders={orders}
          timeRecords={[]}
          onUpdateOrderStatus={async (id, s) => { await parseService.saveOrder({...orders.find(o=>o.id===id)!, status: s}); loadAllData(); }}
          onClockAction={() => {}}
          onCreateReport={async (r) => { await parseService.saveReport(r); loadAllData(); }}
        />
      )}

      {currentUser.role === 'CLIENT' && (
        <ClientView 
          currentUser={currentUser}
          tickets={tickets}
          reports={reports} 
          onCreateTicket={async (t) => { await parseService.saveTicket(t); loadAllData(); }}
        />
      )}
    </div>
  );
}

