         <div className="absolute bottom-[-20%] right-[-10%] w-[80%] h-[80%] bg-purple-600/30 rounded-full blur-[150px] animate-pulse delay-700"></div>
      </div>

      <div className="w-full max-w-[400px] z-10 px-6">
        <div className="bg-white/10 backdrop-blur-2xl border border-white/20 rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-8 shadow-lg">
            <span className="text-4xl font-bold text-white">D</span>
          </div>

          <h2 className="text-2xl font-semibold text-white mb-1">Digital Equipamentos</h2>
          <p className="text-white/50 text-sm mb-8 text-center">Login Unificado • Sistema Integrado</p>

          {error && (
            <div className="mb-6 p-3 bg-red-500/20 text-red-200 rounded-xl text-xs flex items-center gap-2 border border-red-500/30 w-full justify-center">
               <AlertCircle size={14} /> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="w-full space-y-4">
            <div className="group relative">
               <div className="absolute left-4 top-1/2 -translate-y-1/2 text-white/40"><Mail size={18} /></div>
               <input type="email" value={email} onChange={e => setEmail(e.target.value)} required className="w-full pl-12 pr-4 py-4 bg-black/20 border border-white/10 rounded-2xl text-white outline-none focus:border-white/30 transition-all text-sm" placeholder="Seu e-mail" />
            </div>
            <div className="group relative">
               <div className="absolute left-4 top-1/2 -translate-y-1/2 text-white/40"><Lock size={18} /></div>
               <input type="password" value={password} onChange={e => setPassword(e.target.value)} required className="w-full pl-12 pr-4 py-4 bg-black/20 border border-white/10 rounded-2xl text-white outline-none focus:border-white/30 transition-all text-sm" placeholder="Sua senha" />
            </div>
            <button type="submit" disabled={loading} className="w-full py-4 bg-white text-black font-bold rounded-2xl hover:bg-gray-100 transition-all flex items-center justify-center gap-2 mt-4 disabled:opacity-50">
