function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginError, setLoginError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [toasts, setToasts] = useState<{id: string, message: string, type: 'success' | 'error'}[]>([]);

  const [users, setUsers] = useState<User[]>([]);
  const [orders, setOrders] = useState<ServiceOrder[]>([]);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [reports, setReports] = useState<ServiceReport[]>([]);

  const addToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const loadAllData = useCallback(async () => {
    try {
      const [ord, tkt, emp, rep] = await Promise.all([
        parseService.getOrders(),
        parseService.getTickets(),
        parseService.getUsers(),
        parseService.getReports()
      ]);
      setOrders(ord);
      setTickets(tkt);
      setUsers(emp);
      setReports(rep);
    } catch (e) {
      console.error("Erro ao carregar dados:", e);
    }
  }, []);

  useEffect(() => {
    async function init() {
      try {
        const user = await parseService.getCurrentUser();
        if (user) {
          setCurrentUser(user);
          await loadAllData();
        }
      } catch (e) {
        console.error("Erro na sessão:", e);
      } finally {
        setInitialLoading(false);
      }
    }
    init();
  }, [loadAllData]);

  const handleLoginAttempt = async (email: string, pass: string) => {
    setLoading(true);
    setLoginError(null);
    try {
      const user = await parseService.login(email, pass);
      setCurrentUser(user);
      await loadAllData();
      addToast(`Bem-vindo, ${user.name}!`);
    } catch (e: any) {
      setLoginError("Credenciais inválidas.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveUser = async (userData: Partial<User> & { password?: string }) => {
    try {
      await parseService.saveUser(userData);
      await loadAllData();
      addToast(userData.id ? "Perfil atualizado!" : "Novo usuário cadastrado!");
    } catch (e: any) {
      addToast("Erro ao salvar usuário.", "error");
    }
  };

  const handleCreateOrder = async (order: ServiceOrder) => {
    try {
      await parseService.saveOrder(order);
      await loadAllData();
      addToast("Ordem de serviço gerada!");
    } catch (e) {
      addToast("Erro ao criar ordem.", "error");
    }
  };

  const handleUpdateOrderStatus = async (orderId: string, status: OrderStatus) => {
    try {
      await parseService.saveOrder({ id: orderId, status });
      await loadAllData();
      addToast("Status atualizado!");
    } catch (e) {
      addToast("Erro na atualização.", "error");
    }
  };

  const handleCreateReport = async (report: ServiceReport) => {
    try {
      await parseService.saveReport(report);
      await parseService.saveOrder({ id: report.orderId, status: OrderStatus.COMPLETED });
      await loadAllData();
      addToast("Relatório técnico finalizado!");
    } catch (e) {
      addToast("Erro ao salvar relatório.", "error");
    }
  };

  if (initialLoading) {
    return <div className="h-screen bg-slate-950 flex items-center justify-center"><Loader2 className="animate-spin text-white" size={48} /></div>;
  }

  if (!currentUser) {
    return <LoginScreen onLogin={handleLoginAttempt} error={loginError} loading={loading} />;
  }

  return (
    <div className="font-sans antialiased text-slate-900 h-screen overflow-hidden bg-slate-50">
      <ToastContainer toasts={toasts} />

      {currentUser.role === 'ADMIN' && (
        <AdminView 
          orders={orders} 
          employees={users} 
          timeRecords={[]} 
          tickets={tickets}
          hrRequests={[]} 
          reports={reports}
          onCreateOrder={handleCreateOrder}
          onUpdateTicketStatus={async (id, s) => { await parseService.saveTicket({id, status: s}); loadAllData(); }}
          onReplyTicket={async (id, m) => { /* logic */ }}
          onSaveEmployee={handleSaveUser}
        />
      )}

      {currentUser.role === 'EMPLOYEE' && (
        <EmployeeView 
          currentUser={currentUser}
          orders={orders}
          timeRecords={[]}
          onUpdateOrderStatus={handleUpdateOrderStatus}
          onClockAction={() => {}}
          onCreateReport={handleCreateReport}
        />
      )}

      {currentUser.role === 'CLIENT' && (
        <ClientView 
          currentUser={currentUser}
          tickets={tickets}
          reports={reports} 
          onCreateTicket={async (t) => { await parseService.saveTicket(t); loadAllData(); }}
        />
      )}
    </div>
  );
}

