import Parse from 'parse';
import { User, ServiceOrder, Ticket, Role, ServiceReport, TimeRecord, TicketStatus } from '../types';
import { MOCK_USERS, INITIAL_ORDERS, INITIAL_TICKETS, INITIAL_REPORTS, INITIAL_TIME_RECORDS } from './mockStore';

// Configuração do Back4App (Mantida para produção, mas com fallback para Mock)
const APP_ID = "YOUR_BACK4APP_APP_ID";
const JS_KEY = "YOUR_BACK4APP_JS_KEY";

const isMockMode = APP_ID === "YOUR_BACK4APP_APP_ID";

if (!isMockMode && !Parse.applicationId) {
  Parse.initialize(APP_ID, JS_KEY);
  Parse.serverURL = 'https://pg-app.back4app.com/';
}

// In-Memory Storage for Mock Mode
let mockUsers = [...MOCK_USERS];
let mockOrders = [...INITIAL_ORDERS];
let mockTickets = [...INITIAL_TICKETS];
let mockReports = [...INITIAL_REPORTS];
let mockTimeRecords = [...INITIAL_TIME_RECORDS];

export const parseService = {
  async login(email: string, pass: string): Promise<User> {
    if (isMockMode) {
      // Mock Login Logic
      await new Promise(r => setTimeout(r, 800)); // Simulate delay
      const user = mockUsers.find(u => u.email === email);

      // Senha genérica "123" para demo ou qualquer senha se o usuário existir
      if (user) return user;

      // Se não encontrar, tenta criar um admin padrão se for a primeira vez ou erro
      if (email === 'admin@admin.com') return mockUsers.find(u => u.role === 'ADMIN')!;

      throw new Error("Usuário não encontrado (Mock)");
    }

    try {
      const parseUser = await Parse.User.logIn(email, pass);
      return this.mapParseUser(parseUser);
    } catch (error) {
       console.warn("Parse Login Error, falling back to mock if applicable", error);
       throw error;
    }
  },

  async logout() {
    if (!isMockMode) await Parse.User.logOut();
  },

  async getCurrentUser(): Promise<User | null> {
    if (isMockMode) {
      // Na demo, não persistimos sessão complexa, retorna null para forçar login ou o último usuário
      // Para simplificar a demo, vamos pedir login sempre
      return null; 
    }
    const currentUser = Parse.User.current();
    if (!currentUser) return null;
    try {
      await currentUser.fetch();
      return this.mapParseUser(currentUser);
    } catch {
      return this.mapParseUser(currentUser);
    }
  },

  async getUsers(): Promise<User[]> {
    if (isMockMode) return mockUsers;
    const query = new Parse.Query(Parse.User);
    query.limit(1000);
    const results = await query.find();
    return results.map(u => this.mapParseUser(u));
  },

  async saveUser(userData: Partial<User> & { password?: string }): Promise<User> {
    if (isMockMode) {
       if (userData.id) {
          mockUsers = mockUsers.map(u => u.id === userData.id ? { ...u, ...userData } as User : u);
          return mockUsers.find(u => u.id === userData.id)!;
       } else {
          const newUser = { 
            ...userData, 
            id: Date.now().toString(),
            avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${userData.name}`,
            status: 'active'
          } as User;
          mockUsers.push(newUser);
          return newUser;
       }
    }

    if (!userData.id) {
      const user = new Parse.User();
      user.set("username", userData.email);
      user.set("email", userData.email);
      user.set("password", userData.password || "123456");
      user.set("name", userData.name);
      user.set("role", userData.role || 'EMPLOYEE');
      user.set("department", userData.department);
      user.set("position", userData.position);
      user.set("salary", userData.salary);
      user.set("status", userData.status || "active");
      user.set("avatar", `https://api.dicebear.com/7.x/avataaars/svg?seed=${userData.name || 'user'}`);

      const savedUser = await user.signUp();
      return this.mapParseUser(savedUser);
    } else {
      const query = new Parse.Query(Parse.User);
      const user = await query.get(userData.id);

      if (userData.name) user.set("name", userData.name);
      if (userData.role) user.set("role", userData.role);
      if (userData.department) user.set("department", userData.department);
      if (userData.status) user.set("status", userData.status);
      if (userData.password) user.set("password", userData.password);

      await user.save();
      return this.mapParseUser(user);
    }
  },

  async getOrders(): Promise<ServiceOrder[]> {
    if (isMockMode) return mockOrders;
    const query = new Parse.Query("ServiceOrder");
    query.descending("createdAt");
    const results = await query.find();
    return results.map(r => ({ id: r.id, ...r.attributes } as ServiceOrder));
  },

  async saveOrder(order: Partial<ServiceOrder>): Promise<ServiceOrder> {
    if (isMockMode) {
      if (order.id && mockOrders.find(o => o.id === order.id)) {
        mockOrders = mockOrders.map(o => o.id === order.id ? { ...o, ...order } as ServiceOrder : o);
        return mockOrders.find(o => o.id === order.id)!;
      } else {
        const newOrder = { ...order, id: Date.now().toString() } as ServiceOrder;
        mockOrders.unshift(newOrder);
        return newOrder;
      }
    }
    const OrderObj = Parse.Object.extend("ServiceOrder");
    const obj = order.id ? (await new Parse.Query("ServiceOrder").get(order.id)) : new OrderObj();
    await obj.save(order);
    return { ...order, id: obj.id } as ServiceOrder;
  },

  async getTickets(): Promise<Ticket[]> {
    if (isMockMode) return mockTickets;
    const query = new Parse.Query("Ticket");
    query.descending("createdAt");
    const results = await query.find();
    return results.map(r => ({ id: r.id, ...r.attributes } as Ticket));
  },

  async saveTicket(ticket: Partial<Ticket>): Promise<Ticket> {
    if (isMockMode) {
       if (ticket.id && mockTickets.find(t => t.id === ticket.id)) {
          mockTickets = mockTickets.map(t => t.id === ticket.id ? { ...t, ...ticket } as Ticket : t);
          return mockTickets.find(t => t.id === ticket.id)!;
       } else {
          const newTicket = { ...ticket, id: Date.now().toString(), createdAt: new Date().toISOString(), messages: [] } as Ticket;
          mockTickets.unshift(newTicket);
          return newTicket;
       }
    }
    const TicketObj = Parse.Object.extend("Ticket");
    const obj = ticket.id ? (await new Parse.Query("Ticket").get(ticket.id)) : new TicketObj();
    await obj.save(ticket);
    return { ...ticket, id: obj.id } as Ticket;
  },

  async getReports(): Promise<ServiceReport[]> {
    if (isMockMode) return mockReports;
    const query = new Parse.Query("ServiceReport");
    const results = await query.find();
    return results.map(r => ({ id: r.id, ...r.attributes } as ServiceReport));
  },

  async saveReport(report: Partial<ServiceReport>): Promise<ServiceReport> {
    if (isMockMode) {
      const newReport = { ...report, id: Date.now().toString() } as ServiceReport;
      mockReports.push(newReport);
      return newReport;
    }
    const ReportObj = Parse.Object.extend("ServiceReport");
    const obj = new ReportObj();
    await obj.save(report);
    return { ...report, id: obj.id } as ServiceReport;
  },

  async getTimeRecords(): Promise<TimeRecord[]> {
    if (isMockMode) return mockTimeRecords;
    const query = new Parse.Query("TimeRecord");
    query.descending("timestamp");
    const results = await query.find();
    return results.map(r => ({ id: r.id, ...r.attributes } as TimeRecord));
  },

  async saveTimeRecord(record: Partial<TimeRecord>): Promise<TimeRecord> {
    if (isMockMode) {
      const newRecord = { ...record, id: Date.now().toString() } as TimeRecord;
      mockTimeRecords.push(newRecord);
      return newRecord;
    }
    const TimeObj = Parse.Object.extend("TimeRecord");
    const obj = new TimeObj();
    await obj.save(record);
    return { ...record, id: obj.id } as TimeRecord;
  },

  mapParseUser(u: Parse.User): User {
    return {
      id: u.id,
      name: u.get("name") || u.get("username") || "Usuário",
      email: u.get("email"),
      role: u.get("role") as Role,
      avatar: u.get("avatar"),
      department: u.get("department"),
      position: u.get("position"),
      salary: u.get("salary"),
      status: u.get("status")
    };
  }
};

