  // Load Extra Data
  useEffect(() => {
    const loadSaaSData = async () => {
        const logs = await apiService.getAuditLogs();
        const notifs = await apiService.getNotifications();
        const sub = await apiService.getSubscription();
        const inv = await apiService.getInvoices();
